介绍单例对象的类必须保证只有一个实例存在。许多时候整个系统只需要拥有一个全局对象，这样有利于我们调整系统行为 实现思路 一个类能返回一个对象的引用(永远都是同一个)和一个获得该实例的方法(必须是静态方法) getInstance 调用这个方法时，如果类持有的引用不为空就返回这个引用。如果类保持的引用为空，就创建该类的实例返回这个实例的引用 将该类的构造函数定义为私有方法，这样其他处的代码就无法通过调用该类的构造函数来实例化该对象，只有通过该类的静态方法来实现唯一实例。 实现方式 懒汉式 这种lazyloading很明显，不要求线程安全，在多线程不能正常工作 是否lazy初始化 是否多线程安全 实现难度 是 否 易 实现：局部静态变量方式 1234567891011121314151617181920class SingleLazy&#123;private: SingleLazy() &#123; &#125; SingleLazy(const SingleLazy&amp;) = delete; SingleLazy&amp; operator=(const SingleLazy&amp;) = delete;public: static SingleLazy&amp; getInstance() &#123; static SingleLazy single; return single; &#125;&#125;;void test_SingleLazy() &#123; // 多线程可能出现问题 std::cout &lt;&lt; &quot;s1 addr is &quot; &lt;&lt; &amp;SingleLazy::getInstance() &lt;&lt; &quot;
&quot;; std::cout &lt;&lt; &quot;s2 addr is &quot; &lt;&lt; &amp;SingleLazy::getInstance() &lt;&lt; &quot;
&quot;;&#125; 输出如下 12s1 addr is 0x557ab517b151s2 addr is 0x557ab517b151 确实生成了唯一实例，但是存在隐患，多线程可能生成多个实例 饿汉式 是否lazy初始化 是否多线程安全 实现难度 否 是 易 优点：没有加锁，执行效率会提高 缺点：类加载时就初始化，浪费内存 实现：静态成员变量指针方式 定义一个类的静态成员变量，用来控制实现单例 12345678910111213141516171819202122232425262728293031323334class SingleHungry&#123;private: SingleHungry() &#123; &#125; SingleHungry(const SingleHungry&amp;) = delete; SingleHungry&amp; operator=(const SingleHungry&amp;) = delete;public: static SingleHungry* getInstance() &#123; if(single == nullptr) &#123; single = new SingleHungry(); &#125; return single; &#125;private: static SingleHungry *single;&#125;;// 饿汉式初始化SingleHungry *SingleHungry::single = SingleHungry::getInstance();void thread_func(int num) &#123; std::cout &lt;&lt; &quot;this is thread &quot; &lt;&lt; num &lt;&lt; &quot;
&quot;; std::cout &lt;&lt; &quot;Instance is &quot; &lt;&lt; SingleHungry::getInstance() &lt;&lt; &quot;
&quot;;&#125;void test_SingleHungry() &#123; std::cout &lt;&lt; &quot;s1 addr is &quot; &lt;&lt; SingleHungry::getInstance() &lt;&lt; &quot;
&quot;; std::cout &lt;&lt; &quot;s2 addr is &quot; &lt;&lt; SingleHungry::getInstance() &lt;&lt; &quot;
&quot;; for(int i = 0; i &lt; 3; i++) &#123; std::thread ti(thread_func , i); ti.join(); &#125;&#125; 输出结果如下 12345678s1 addr is 0x56334e3ae2b0s2 addr is 0x56334e3ae2b0this is thread 0Instance is 0x56334e3ae2b0this is thread 1Instance is 0x56334e3ae2b0this is thread 2Instance is 0x56334e3ae2b0 可见无论是单线程还是多线程模式下，通过静态成员变量的指针实现的单例类都是唯一的。 但是无论是饿汉式还是懒汉式都存在一个问题，那就是什么时候释放内存？多线程情况下，释放内存就很难了，还有二次释放内存的风险。 下面我们定义一个单例类并用懒汉式调用 12345678910111213141516171819202122232425262728293031323334353637383940414243444546class SinglePointer &#123;private: SinglePointer() &#123; &#125; SinglePointer(const SinglePointer&amp;) = delete; SinglePointer&amp; operator=(const SinglePointer&amp;) = delete;public: static SinglePointer* getInstance() &#123; if(single != nullptr) &#123; return single; &#125; Lock.lock(); if(single != nullptr) &#123; Lock.unlock(); return single; &#125; single = new SinglePointer(); Lock.unlock(); return single; &#125;private: static SinglePointer *single; static std::mutex Lock;&#125;;std::mutex SinglePointer::Lock;SinglePointer *SinglePointer::single = nullptr;void thread_func_ptr(int num) &#123; std::cout &lt;&lt; &quot;this thread is &quot; &lt;&lt; num &lt;&lt; &quot;
&quot;; std::cout &lt;&lt; &quot;Instance is &quot; &lt;&lt; SinglePointer::getInstance() &lt;&lt; &quot;
&quot;;&#125;void test_SinglePointer() &#123; std::cout &lt;&lt; &quot;s1 addr is &quot; &lt;&lt; SinglePointer::getInstance() &lt;&lt; &quot;
&quot;; std::cout &lt;&lt; &quot;s2 addr is &quot; &lt;&lt; SinglePointer::getInstance() &lt;&lt; &quot;
&quot;; for(int i = 0; i &lt; 3; i++) &#123; std::thread ti(thread_func_ptr , i); ti.join(); &#125; // 何时释放new的对象?造成内存泄漏&#125; 输出结果如下： 12345678s1 addr is 0x55cede7582d0s2 addr is 0x55cede7582d0this thread is 0Instance is 0x55cede7582d0this thread is 1Instance is 0x55cede7582d0this thread is 2Instance is 0x55cede7582d0 此时生成的单例对象的内存空间还没回收，这是个问题，另外如果多线程情况下多次delete也会造成崩溃。 所以需要一种自动回收内存的机制帮助我们回收内存，所以可以使用智能指针来做这个操作 实现方式：智能指针方式 可以利用智能指针自动回收内存的机制设计单例类 123456789101112131415161718192021222324252627282930313233343536373839404142class SingleAuto&#123;private: SingleAuto() &#123; &#125; SingleAuto(const SingleAuto&amp;) = delete; SingleAuto&amp; operator=(const SingleAuto&amp;) = delete;public: ~SingleAuto() &#123; std::cout &lt;&lt; &quot;single auto delete success
&quot;; &#125; static std::shared_ptr&lt;SingleAuto&gt; getInstance() &#123; if(single != nullptr) &#123; return single; &#125; Lock.lock(); if(single != nullptr) &#123; Lock.unlock(); return single; &#125; single = std::shared_ptr&lt;SingleAuto&gt;(new SingleAuto()); Lock.unlock(); return single; &#125;private: static std::shared_ptr&lt;SingleAuto&gt; single; static std::mutex Lock;&#125;;std::shared_ptr&lt;SingleAuto&gt; SingleAuto:: single = nullptr;std::mutex SingleAuto::Lock;void test_SingleAuto() &#123; auto sp1 = SingleAuto::getInstance(); auto sp2 = SingleAuto::getInstance(); std::cout &lt;&lt; &quot;sp1 is &quot; &lt;&lt; sp1 &lt;&lt; &quot;
&quot;; std::cout &lt;&lt; &quot;sp2 is &quot; &lt;&lt; sp2 &lt;&lt; &quot;
&quot;; // 存在隐患，可以手动删除裸指针，造成崩溃，因为会二次释放内存 // delete sp1.get();&#125; 输出如下 12sp1 is 0x56252c7252f0sp2 is 0x56252c7252f0 智能指针方式不存在内存泄漏，但是有一个隐患就是单例类的析构函数是public,如果被人手动调用会存在崩溃问题，比如将上面的test_SingleAuto中的注释打开，程序会崩溃。 实现：辅助类智能指针单例模式 智能指针在构造的时候可以指定删除器，所以可以传递一个辅助类或者辅助函数帮助智能指针回收内存时调用我们指定的析构函数 12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758596061626364656667// NOTE: safe deletorr// 防止外界deletor// 声明辅助类// 该类定义放函数调用SingleAutoSafe析构函数// 不可以提前声明辅助类，编译器会报 incomplete type// class SafeDeletor// 所以要提前定义辅助类class SingleAutoSafe;class SafeDeletor &#123;public: void operator()(SingleAutoSafe* s) &#123; std::cout &lt;&lt; &quot;this is safe deletor operator()
&quot;; delete s; &#125;&#125;;void SafeDeletorFunc(SingleAutoSafe* s) &#123; std::cout &lt;&lt; &quot;this is safe deletor func
&quot;; delete s;&#125;class SingleAutoSafe &#123;private: SingleAutoSafe() &#123; &#125; ~SingleAutoSafe() &#123; std::cout &lt;&lt; &quot;this is sing auto safe deletor
&quot;; &#125; SingleAutoSafe(const SingleAutoSafe&amp;) = delete; SingleAutoSafe&amp; operator=(const SingleAutoSafe&amp;) = delete; friend class SafeDeletor; friend void SafeDeletorFunc(SingleAutoSafe* s);public: static std::shared_ptr&lt;SingleAutoSafe&gt; getInstance() &#123; if(single != nullptr) &#123; return single; &#125; Lock.lock(); if(single != nullptr) &#123; Lock.unlock(); return single; &#125; // NOTE:额外指定删除器 // single = std::shared_ptr&lt;SingleAutoSafe&gt;(new SingleAutoSafe() , SafeDeletor()); // NOTE:额外指定删除函数 single = std::shared_ptr&lt;SingleAutoSafe&gt;(new SingleAutoSafe() , SafeDeletorFunc); Lock.unlock(); return single; &#125;private: static std::shared_ptr&lt;SingleAutoSafe&gt; single; static std::mutex Lock;&#125;;std::shared_ptr&lt;SingleAutoSafe&gt; SingleAutoSafe::single = nullptr;std::mutex SingleAutoSafe::Lock;void test_SingleAutoSafe() &#123; auto sp1 = SingleAutoSafe::getInstance(); auto sp2 = SingleAutoSafe::getInstance(); std::cout &lt;&lt; &quot;sp1 is &quot; &lt;&lt; sp1 &lt;&lt; &quot;
&quot;; std::cout &lt;&lt; &quot;sp2 is &quot; &lt;&lt; sp2 &lt;&lt; &quot;
&quot;; // 此时无法访问析构函数，非常安全 // delete sp1.get();&#125; 输出如下 123sp1 is 0x563f192162b0sp2 is 0x563f192162b0this is safe deletor func SafeDeletor要写在SingleAutoSafe上边，并且SafeDeletor要声明为SingleAutoSafe类的友元类，这样就可以访问SingleAutoSafe的析构函数了。 我们在构造single时制定了SafeDeletor(),single在回收时，会调用SingleAutoSafe的仿函数，从而完成内存的销毁。 并且SingleAutoSafe的析构函数为私有的无法被外界手动调用了。 通过辅助类调用单例类的析构函数保证了内存释放的安全性和唯一性。这种方式是生产中常用的。如果将test_SingleAutoSafe的注释打开，手动删除在编译阶段就会报错，达到了代码安全的目的。 通过单例模板类1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253545556575859606162636465666768#pragma once#include &lt;iostream&gt;#include &lt;memory&gt;#include &lt;mutex&gt;#include &lt;thread&gt;template&lt;typename T&gt;class TD;template&lt;typename T&gt;class Single_T;template&lt;typename T&gt;class SafeDeletor &#123;public: void operator()(T* s) &#123; std::cout &lt;&lt; &quot;this is safe deletor operator()
&quot;; delete s; &#125;&#125;;template&lt;typename T&gt;void SafeDeletorFunc(T* s) &#123; std::cout &lt;&lt; &quot;this is safe deletor func
&quot;; delete s;&#125;template&lt;typename T&gt;class Single_T &#123;protected: Single_T() = default; ~Single_T() &#123; std::cout &lt;&lt; &quot;this is single template deletor
&quot;; &#125; Single_T(const Single_T&amp;) = delete; Single_T&amp; operator=(const Single_T&amp;) = delete; friend class SafeDeletor&lt;T&gt;; friend void SafeDeletorFunc&lt;T&gt;(T* s);public: static std::shared_ptr&lt;T&gt; getInstance() &#123; if(single != nullptr) &#123; return single; &#125; Lock.lock(); if(single != nullptr) &#123; Lock.unlock(); return single; &#125; // NOTE:额外指定删除器 // single = std::shared_ptr&lt;T&gt;(new T, SafeDeletor&lt;T&gt;()); // NOTE:额外指定删除函数 single = std::shared_ptr&lt;T&gt;(new T , SafeDeletorFunc&lt;T&gt;); Lock.unlock(); return single; &#125;private: static std::shared_ptr&lt;T&gt; single; static std::mutex Lock;&#125;;// NOTE: 模板类的static成员要放在hpp文件内初始化template&lt;typename T&gt;std::shared_ptr&lt;T&gt; Single_T&lt;T&gt;::single = nullptr;template&lt;typename T&gt;std::mutex Single_T&lt;T&gt;::Lock; 12345678910111213141516171819202122232425262728293031// 使用std::call_once#pragma once#include &lt;mutex&gt;#include &lt;memory&gt;#include &lt;iostream&gt;template&lt;typename T&gt;class SingleTon &#123;protected: explicit SingleTon() = default; SingleTon(const SingleTon&amp; ) = delete; SingleTon&amp; operator=(const SingleTon&amp;) = delete; ~SingleTon() &#123; std::cout &lt;&lt; &quot;This is SingleTon deletor&quot; &lt;&lt; std::endl; &#125; static std::shared_ptr&lt;T&gt; single;public: static std::shared_ptr&lt;T&gt; getInstance() &#123; static std::once_flag flag; std::call_once(flag, [&amp;]()&#123; single = std::make_shared&lt;T&gt;(new T); &#125;); return single; &#125;&#125;;template&lt;typename T&gt;std::shared_ptr&lt;T&gt; SingleTon&lt;T&gt;::single = nullptr; 使用方式：我们只需要定一个单例类，继承这个模板，并将构造和析构都设置为私有，同时设置友元保证自己的析构和构造可以被友元调用即可。 1234567891011121314151617class SingleNet : public Single_T&lt;SingleNet&gt; &#123;private: SingleNet() = default; ~SingleNet() = default; SingleNet(const SingleNet&amp;) = delete; SingleNet&amp; operator=(const SingleNet&amp;) = delete; friend class SafeDeletor&lt;SingleNet&gt;; friend class Single_T&lt;SingleNet&gt;; friend void SafeDeletorFunc&lt;SingleNet&gt;(SingleNet* s);&#125;;void test_Single_T() &#123; auto sp1 = SingleNet::getInstance(); auto sp2 = SingleNet::getInstance(); std::cout &lt;&lt; &quot;sp1 is &quot; &lt;&lt; sp1 &lt;&lt; &quot;
&quot;; std::cout &lt;&lt; &quot;sp2 is &quot; &lt;&lt; sp2 &lt;&lt; &quot;
&quot;;&#125;

利用条件变量实现线程安全队列 本文介绍如何使用条件变量控制并发的同步操作 条件变量试想有一个线程A一直输出1，另一个线程B一直输出2。我想让两个线程交替输出1，2，1，2…之类的效果，该如何实现？有的同学可能会说不是有互斥量mutex吗？可以用一个全局变量num表示应该哪个线程输出，比如num为1则线程A输出1，num为2则线程B输出2，mutex控制两个线程访问num，如果num和线程不匹配，就让该线程睡一会，这不就实现了吗？比如线程A加锁后发现当前num为2则表示它不能输出1，就解锁，将锁的使用权交给线程A，线程B就sleep一会。 12345678910111213141516171819202122232425262728293031323334int num = 1;std::mutex mtx;void PoorImplemention() &#123; std::thread t1( []() &#123; while ( true ) &#123; &#123; std::lock_guard&lt;std::mutex&gt; lock( mtx ); if ( num == 1 ) &#123; std::cout &lt;&lt; &quot;This thread A print &quot; &lt;&lt; num &lt;&lt; std::endl; ; num++; &#125; &#125; std::this_thread::sleep_for( std::chrono::seconds( 1 ) ); &#125; &#125; ); std::thread t2( []() &#123; while ( true ) &#123; &#123; std::lock_guard&lt;std::mutex&gt; lock( mtx ); if ( num == 2 ) &#123; std::cout &lt;&lt; &quot;This thread B print &quot; &lt;&lt; num &lt;&lt; std::endl; num--; &#125; &#125; std::this_thread::sleep_for( std::chrono::seconds( 1 ) ); &#125; &#125; ); t1.join(), t2.join();&#125; PoorImplement虽然能实现我们交替打印的功能，会造成消息处理的不及时处理，因为线程A要循环检测num值，如果num不为1,则线程A就睡眠了，在线程A睡眠这段时间里面很可能线程B已经处理完了，此时A还在睡眠，是对资源的浪费，也错过了最佳的处理时机。所以我们提出了用条件变量来通知线程的机制，当线程A发现条件不满足时可以挂起，等待线程B通知，线程B通知线程A后，A被唤醒继续处理 123456789101112131415161718192021222324252627282930313233int num = 1;std::mutex mtx;std::condition_variable cvA , cvB;void ReasonableImplemention() &#123; std::thread t1( []() &#123; while ( true ) &#123; std::unique_lock&lt;std::mutex&gt; lock(mtx); cvA.wait(lock , []()&#123; return num == 1; &#125;); num++; std::cout &lt;&lt; &quot;Thread A print 1....&quot; &lt;&lt; std::endl; cvB.notify_one(); &#125; &#125; ); std::thread t2( []() &#123; while ( true ) &#123; std::unique_lock&lt;std::mutex&gt; lock(mtx); cvB.wait(lock , []()&#123; return num == 2; &#125;); num--; std::cout &lt;&lt; &quot;Thread B print 2....&quot; &lt;&lt; std::endl; cvA.notify_one(); &#125; &#125; ); t1.join(), t2.join();&#125; 当条件不满足时(num !&#x3D; 1)cvA.wait就会挂起，等待线程B通知线程A唤醒，线程B采用cvA.notify_one。这么做的好处是线程交替处理十分及时，比起sleep的方式，我们可以从控制台看出差异效果，sleep的方式看出日志基本是每隔1秒才打印一次，效率不高 线程安全队列之前我们实现过线程安全的栈，对于pop操作，我们如果在线程中调用empty判断是否为空，如果不为空，则pop，因为empty和pop内部分别加锁，是两个原子操作，导致pop时可能会因为其他线程提前pop导致队列为空，从而引发崩溃。我们当时的处理方式是实现了两个版本的pop，一种是返回智能指针类型，一种通过参数为引用的方式返回。对于智能指针版本我们发现队列为空则返回空指针，对于引用版本，发现队列为空则抛出异常，这么做并不是很友好，所以我们可以通过条件变量完善之前的程序，不过这次我们重新实现一个线程安全队列。 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104105106107108109110111112113114115116117118119120121122123124125#pragma once#include &lt;memory&gt;#include &lt;mutex&gt;#include &lt;condition_variable&gt;#include &lt;queue&gt;template &lt;typename T&gt; class Queue_Thread_Safe &#123;private: std::queue&lt;T&gt; data_; std::mutex mtx_; std::condition_variable cvq_;public: Queue_Thread_Safe() = default; Queue_Thread_Safe( const Queue_Thread_Safe &amp; ); void push( T &amp;&amp; ); void wait_and_pop( T &amp;&amp; ); std::shared_ptr&lt;T&gt; wait_and_pop(); bool try_pop( T&amp; ); std::shared_ptr&lt;T&gt; try_pop(); bool empty();&#125;;template &lt;typename T&gt;Queue_Thread_Safe&lt;T&gt;::Queue_Thread_Safe( const Queue_Thread_Safe &amp;other ) &#123; std::lock_guard&lt;std::mutex&gt; lock( other.mtx_ ); this-&gt;data_ = other.data_;&#125;template &lt;typename T&gt; void Queue_Thread_Safe&lt;T&gt;::push( T &amp;&amp;param ) &#123; std::lock_guard&lt;std::mutex&gt; lock( mtx_ ); data_.emplace( param ); // NOTE: 这里通知线程是因为如果别的线程有pop操作，由于队列可能是空的会被挂起，所以要通知一个线程 cvq_.notify_one();&#125;template &lt;typename T&gt; void Queue_Thread_Safe&lt;T&gt;::wait_and_pop( T &amp;&amp;value ) &#123; std::unique_lock&lt;std::mutex&gt; lock( mtx_ ); cvq_.wait( lock, [this]() &#123; return !data_.empty(); &#125; ); value = data_.front(); data_.pop();&#125;template &lt;typename T&gt; std::shared_ptr&lt;T&gt; Queue_Thread_Safe&lt;T&gt;::wait_and_pop() &#123; std::unique_lock&lt;std::mutex&gt; lock( mtx_ ); cvq_.wait( lock, [this]() &#123; return !data_.empty(); &#125; ); std::shared_ptr&lt;T&gt; res( std::make_shared&lt;T&gt;( data_.front() ) ); data_.pop(); return res;&#125;template&lt;typename T&gt; bool Queue_Thread_Safe&lt;T&gt;::try_pop(T&amp; value) &#123; std::unique_lock&lt;std::mutex&gt; lock(mtx_); if(empty()) &#123; return false; &#125; value = data_.front(); return true;&#125;template&lt;typename T&gt;std::shared_ptr&lt;T&gt; Queue_Thread_Safe&lt;T&gt;::try_pop() &#123; std::unique_lock&lt;std::mutex&gt; lock(mtx_); cvq_.wait(lock, [this]()&#123; return !data_.empty(); &#125;); std::shared_ptr&lt;T&gt; res( std::make_shared&lt;T&gt;(data_.front()) ); data_.pop(); return res;&#125;template&lt;typename T&gt; bool Queue_Thread_Safe&lt;T&gt;::empty() &#123; // WARN:这里记得要加个锁，因为在判断队列是否为空的时候，要保证状态一致 std::unique_lock&lt;std::mutex&gt; lock(mtx_); return data_.empty();&#125;// 测试函数void test_thread_safe_queue() &#123; thread_safe_queue&lt;int&gt; safe_queue; std::mutex mtx_print; std::thread producer( [&amp;]() &#123; for ( int i = 0;; i++ ) &#123; safe_queue.push( std::forward&lt;decltype(i)&gt;(i) ); &#123; std::lock_guard&lt;std::mutex&gt; lock_print( mtx_print ); std::cout &lt;&lt; &quot;producer push data is &quot; &lt;&lt; i &lt;&lt; std::endl; &#125; std::this_thread::sleep_for( std::chrono::milliseconds( 200 ) ); &#125; &#125; ); std::thread consumer1( [&amp;]() &#123; while ( true ) &#123; auto data = safe_queue.wait_and_pop(); &#123; std::lock_guard&lt;std::mutex&gt; lock_print( mtx_print ); std::cout &lt;&lt; &quot;consumer1 wait and pop data is &quot; &lt;&lt; *data &lt;&lt; std::endl; &#125; std::this_thread::sleep_for( std::chrono::milliseconds( 500 ) ); &#125; &#125; ); std::thread consumer2( [&amp;]() &#123; while ( true ) &#123; auto data = safe_queue.try_pop(); if ( data != nullptr ) &#123; &#123; std::lock_guard&lt;std::mutex&gt; lock_print( mtx_print ); std::cout &lt;&lt; &quot;consumer2 try pop data is &quot; &lt;&lt; *data &lt;&lt; std::endl; &#125; &#125; std::this_thread::sleep_for( std::chrono::milliseconds( 500 ) ); &#125; &#125; ); producer.join(); consumer1.join(); consumer2.join();&#125; 输出如下: 123456789101112131415161718192021222324252627282930producer push data is 0consumer1 wait and pop data is 0producer push data is 1producer push data is 2consumer2 try pop data is 1consumer1 wait and pop data is 2producer push data is 3producer push data is 4consumer1 wait and pop data is 3consumer2 try pop data is 4producer push data is 5producer push data is 6producer push data is 7consumer2 try pop data is 5consumer1 wait and pop data is 6producer push data is 8producer push data is 9consumer2 try pop data is 7consumer1 wait and pop data is 8producer push data is 10producer push data is 11producer push data is 12consumer2 try pop data is 9consumer1 wait and pop data is 10producer push data is 13producer push data is 14consumer2 try pop data is 11consumer1 wait and pop data is 12producer push data is 15producer push data is 16 C++异步在C++中future, promise和async是C++标准库中的一些重要概念，它们可以用于实现异步编程。它们的具体用法可以参考官方文档 。 async用法std::async是用于异步执行函数的函数模板，它返回一个future对象，该对象用于获取函数的返回值 例子: 123456789101112131415161718192021222324252627#include &lt;iostream&gt;#include &lt;chrono&gt;#include &lt;future&gt;#include &lt;thread&gt;// 定义一个异步任务std::string FetchFromDB(const std::string&amp; query) &#123; //模拟一个异步任务，比如从数据库中获取数据 std::this_thread::sleep_for(std::chrono::milliseconds(200)); return &quot;Data: &quot; + query;&#125;void async_demo() &#123; // NOTE: 使用std::async异步调用FetchFromDB std::future&lt;std::string&gt; resultFromDB = std::async(std::launch::async , FetchFromDB , &quot;Data&quot;); // 主线程中做其他事情 std::cout &lt;&lt; &quot;Doing something else&quot; &lt;&lt; std::endl; // 从future对象中获取数据 std::string dbData = resultFromDB.get(); std::cout &lt;&lt; dbData &lt;&lt; std::endl;&#125;int main() &#123; async_demo(); return 0;&#125; 在这个事例中，std::async创建了一个新的线程(或从内部线程池中挑选了一个线程)并自动与一个std::promise对象相关联。std::promise对象被传递给FetchFromDB函数，函数返回值被存储在std::future对象中，在主线程中，我们可以使用std::future::get方法从std::future对象中获取数据。注意，在使用std::async的情况下，我们必须使用std::launch::async标志来明确表示我们希望函数异步执行。 输出如下： 12Doing something elseData: Data async的启动策略std::async函数可以接受几个不同的启动策略，这些策略在std::launch枚举中定义。除了std::launch::async之外，还有以下启动策略 std::launch::deferred:这种策略意味着任务将在调用std::future::get()或std::future::wait()函数时延迟执行。换句话说，任务将在需要结果时同步执行。 std::launch::async | std::launch::deferred: 这种策略是上面两个策略的组合。任务可以在一个单独的线程上异步执行，也可以延迟执行，具体取决于实现。 默认情况下，std::async使用std::launch::async|std::launch::deferred策略。这意味着任务可能异步执行，也可能延迟执行，具体取决于实现。需要注意的是，不同的编译器和操作系统可能会有不同的默认行为。 future的wait和getstd::future::get()和std::future::wait()是c++中用于处理异步人物的两个方法，它们的功能和用法有一些重要区别。 std::future::get() std::future::get()是一个阻塞调用，用于获取std::future对象表示的值或异常。如果异步任务还没有完成，get()会阻塞当前线程，直到任务完成。如果任务已经完成，get()会立即返回结果。重要的是，get()只能调用一次，因为它会移动或消耗掉std::future对象的状态。一旦get()被调用，std::future对象就不能再被用来获取结果。 std::future::wait() std::future::wait也是一个阻塞调用，但它与get()的主要区别在与wait()不会返回任务的结果。它只是等待异步任务完成。如果任务已经完成，wait()会立即返回。如果任务没有完成，wait()会阻塞当前线程，直到任务完成。与get()不同，wait()可以被多次调用，它不会消耗掉std::future对象的状态。 总结： std::future::get()用于获取并返回任务的结果，而std::future::wait()只是等待任务完成。 get()只能被调用一次，而wait()可以被多次调用。 如果任务还没有完成，get()和wait()都会阻塞当前线程，但get()会一直阻塞知道任务完成并返回结果，而wait()只是在等待任务完成。 你可以使用std::future的wait_for()或wait_until()方法来检查异步操作是否完成。这些方法返回一个表示操作状态的std::future_status的值 12345if(fut.wait_for(std::chrono::seconds(0)) == std::future_status::ready) &#123;// 操作完成&#125; else &#123;// 操作尚未完成&#125; 将任务和future关联std::packaged_task和std::future是C++11中引入的两个类，它们用于处理异步任务的结果。 std::packaged_task是一个可调用目标，它包装了一个任务，该任务可以在另一个线程上运行。它可以捕获任务的返回值或异常，并将其存储在std::future对象中，一边以后使用。 以下是使用std::packaged_task和std::future对象的基本步骤： 创建一个std::packaged_task对象，该对象包装了要执行的任务。 调用std::packaged_task对象的get_future()方法，该方法返回一个与任务关联的std::future对象 在另一个线程上调用std::packaged_task对象的operator()，用于执行任务 在需要任务结果的地方，调用与任务关联的std::future对象的get()方法，以获取任务的返回值或异常 例子: 123456789101112131415161718192021int mytask() &#123; std::this_thread::sleep_for(std::chrono::seconds(5)); std::cout &lt;&lt; &quot;my task run 5s&quot; &lt;&lt; std::endl; return 52;&#125;void use_package() &#123; // 创建了一个包装了任务的std::packaged_task对象 std::packaged_task&lt;int()&gt; task(mytask); // 获取与任务关联的std::future对象 std::future&lt;int&gt; result = task.get_future(); // 在另一个线程上执行任务 std::thread t(std::move(task)); // NOTE: std::packaged_task对象不能被复制，只能移动。因为std::packaged_task内部保存了一个对应的执行任务，这个任务应该被唯一执行，并且任务的结果也应该唯一保存，因此不允许复制，只能移动。 t.detach(); // 将线程与主线程分离，以便主线程可以等待任务完成 // 等待任务完成并获取结果 int value = result.get(); // get在获取结果之前会阻塞当前线程 std::cout &lt;&lt; &quot;The result is: &quot; &lt;&lt; value &lt;&lt; std::endl;&#125; 在上面的实例中，我们创建了一个包装了任务的std::packaged_task对象，并获取了与任务关联的std::future对象，然后，我们在另一个线程上执行任务，并等待任务完成并获取结果。最后，我们输出结果。 我们可以使用std::function和std::packaged_task来包装带参数的函数。std::packaged_task是一个模板类，他包装了一个可调用对象，并允许我们将其作为异步任务传递。 promise的用法C++11引入了std::promise和std::future两个类，用于实现异步编程。std::promise用于在某一线程中设置某个值或异常，而std::future则用于在另一线程中获取这个值或异常。 例子： 12345678910111213141516void set_value(std::promise&lt;int&gt; prom) &#123; prom.set_value(10); std::cout &lt;&lt; &quot;promise set value successfully by the thread
&quot;;&#125;void promise_demo() &#123; std::promise&lt;int&gt; prom; std::future&lt;int&gt; fut = prom.get_future(); std::thread t1(set_value , std::move(prom)); std::cout &lt;&lt; &quot;Waiting for the thread to set value ...
&quot;; std::cout &lt;&lt; &quot;Value set by the thread: &quot; &lt;&lt; fut.get() &lt;&lt; &quot;
&quot;; t1.join();&#125; 输出: 123Waiting for the thread to set value ...Value set by the thread: promise set value successfully by the thread10 在上面的代码中，我们首先创建了一个std::promise&lt;int&gt;对象，然后通过调用get_future()方法获取与之相关联的std::future&lt;int&gt;对象。然后，我们在新线程中通过调用set_value()方法设置promise的值，并在主线程中通过调用fut.get()方法获取这个值。注意，在调用fut.get()方法时，如果promise的值还没有被设置，则该方法会阻塞当前线程，直到值被设置为止。 除了set_value方法外，std::promise还有一个set_exception()方法，用于设置异常。该方法接受一个std::exception_ptr参数，该参数可以通过调用std::current_exception()方法获取。 例子如下： 1234567891011121314151617181920212223242526272829void set_exception(std::promise&lt;void&gt; prom) &#123; try &#123; // 抛出一个异常 throw std::runtime_error(&quot;An error occurred
&quot;); &#125; catch(...) &#123; // NOTE: ... 表示捕获任意类型的异常 // 设置promise的异常 prom.set_exception(std::current_exception()); &#125;&#125;void promise_exception_demo() &#123; std::promise&lt;void&gt; prom; // 获取与promise相关联的对象 std::future&lt;void&gt; fut = prom.get_future(); // 创建一个线程 std::thread t1(set_exception , std::move(prom)); // 在主线程获取future的异常 try&#123; std::cout &lt;&lt; &quot;Waiting for the thread to set exception....
&quot;; fut.get(); &#125; catch(const std::exception&amp; e) &#123; std::cout &lt;&lt; &quot;Exception set by the thread: &quot; &lt;&lt; e.what() &lt;&lt; &quot;
&quot;; &#125; t1.join();&#125; 输出如下 12Waiting for the thread to set exception....Exception set by the thread: An error occurred 当然我们在使用std::promise时要注意一点，如果std::promise被释放了，而其他线程还未使用与std::promise关联的future,当其使用这个std::future时会报错。 例子： 123456789101112131415void use_promise_destruct() &#123; std::thread t; std::future&lt;int&gt; fut; &#123; std::promise&lt;int&gt; prom; fut = prom.get_future(); t = std::thread(set_value , std::move(prom)); &#125; std::cout &lt;&lt; &quot;Waiting for the thread to set value ...
&quot;; std::cout &lt;&lt; &quot;Value set by the thread: &quot; &lt;&lt; fut.get() &lt;&lt; &quot;
&quot;; t.join();&#125; 随着局部&#125;的结束，prom可能被释放也可能会被延迟释放，如果立即释放则fut.get()获取的值会报error_value的错误 共享型的future当我们需要多个线程等待同一个执行结果时，需要使用std::shared_future 以下是一个适合使用std::shared_future的场景，多个线程等待一个异步操作的结果 假设你有一个异步任务，需要多个线程等待其完成，然后这些线程需要访问任务的结果。在这种情况下，你可以使用std::shared_future来共享异步结果 1234567891011121314151617181920212223242526272829void myFunction(std::promise&lt;int&gt;&amp;&amp; prom) &#123; // 模拟一些工作 std::this_thread::sleep_for(std::chrono::seconds(1)); prom.set_value(42);&#125;void threadFunction(std::shared_future&lt;int&gt; fut) &#123; try&#123; int result = fut.get(); std::cout &lt;&lt; &quot;Result: &quot; &lt;&lt; result &lt;&lt; &quot;
&quot;; &#125; catch(const std::future_error&amp; e) &#123; std::cout &lt;&lt; &quot;Future error: &quot; &lt;&lt; e.what() &lt;&lt; std::endl; &#125;&#125;void shared_future_demo() &#123; std::promise&lt;int&gt; prom; std::shared_future&lt;int&gt; shared_fut = prom.get_future(); // NOTE: 第一个线程先去执行任务，后面两个线程等待std::shared_future的值 std::thread myThread1(myFunction , std::move(prom)); std::thread myThread2(threadFunction, shared_fut); std::thread myThread3(threadFunction , shared_fut); myThread1.join() , myThread2.join() , myThread3.join();&#125; 我们创建了一个std::promise&lt;int&gt;对象prom和一个与之关联的std::shared_future&lt;int&gt;对象shared_fut。然后我们将promise对象移动到另一个线程myThread1中，该线程将执行myFunction函数，并在完成后设置prom的值，那么shared_fut.get()将返回该值。这些线程可以同时访问和等待future对象的结果，而不会相互干扰 注意，如果一个future被移动给两个shared_future是错误的 12345678910111213141516171819void threadFunction(std::shared_future&lt;int&gt; fut) &#123; try&#123; int result = fut.get(); std::cout &lt;&lt; &quot;Result: &quot; &lt;&lt; result &lt;&lt; &quot;
&quot;; &#125; catch(const std::future_error&amp; e) &#123; std::cout &lt;&lt; &quot;Future error: &quot; &lt;&lt; e.what() &lt;&lt; std::endl; &#125;&#125;void shared_future_demo() &#123; std::promise&lt;int&gt; prom; std::shared_future&lt;int&gt; shared_fut = prom.get_future(); std::thread myThread1(myFunction , std::move(prom)); std::thread myThread2(threadFunction, std::move(shared_fut)); std::thread myThread3(threadFunction , std::move(shared_fut)); myThread1.join() , myThread2.join() , myThread3.join();&#125; 这种用法是错误的，一个future通过隐式构造传递给shared_future之后，这个shared_future被移动传递给两个线程是不合理的，因为第一次移动之后shared_future的生命周期被转移了，接下俩myThread3构造时用的std::move(future)future已经失效了，会报错，一般都是no state之类的错误。 异常处理std::future是一个模板类，它用于表示一个可能还没有准备好的异步操作的结果。你可以通过调用std::future::get()方法来获取这个结果。如果在获取结果是发生了异常，那么std::future::get()会重新抛出这个异常 例子： 123456789101112void may_throw() &#123; throw std::runtime_error(&quot;Oops, something went wrong!&quot;);&#125;void get_future_error() &#123; // 创建一个异步任务 std::future&lt;void&gt; result(std::async(std::launch::async , may_throw)); try &#123; result.get(); &#125; catch(const std::exception&amp; e) &#123; std::cerr &lt;&lt; &quot;Caught exception: &quot; &lt;&lt; e.what() &lt;&lt; std::endl; &#125;&#125; 在这个例子中，我们创建了一个异步任务may_throw，这个任务会抛出一个异常。然后，我们创建一个std::future对象result来表示这个任务的结果。在get_future_error函数中，我们调用result.get()来获取任务的结果。如果在获取结果时发生了异常，那么result.get()会重新抛出这个异常，然后我们在catch块中捕获了并打印这个异常。 输出： 1Caught exception: Oops, something went wrong! 线程池我们可以利用上面提到的std::packaged_task和std::promise构建线程池，提高程序的并发能力 线程池的知识: 线程池是一种多线程处理形式，它处理过程中将任务添加到队列，然后在创建线程后自动启动这些任务。线程池线程都是后台线程。每个线程都使用默认的堆栈大小，以默认的优先级运行，并处于多线程单元中。如果某个线程在托管代码中空闲（如正在等待某个事件）,则线程池将插入另一个辅助线程来使所有处理器保持繁忙。如果所有线程池线程都始终保持繁忙，但队列中包含挂起的工作，则线程池将在一段时间后创建另一个辅助线程但线程的数目永远不会超过最大值。超过最大值的线程可以排队，但他们要等到其他线程完成后才启动。 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104105106107108109110111112113114115116117#pragma once#include &lt;iostream&gt;#include &lt;future&gt;#include &lt;atomic&gt;#include &lt;thread&gt;#include &lt;condition_variable&gt;#include &lt;vector&gt;#include &lt;mutex&gt;#include &lt;queue&gt;#include &lt;functional&gt;template &lt;typename T&gt; class TD;class ThreadPool &#123;public: ThreadPool( const ThreadPool &amp; ) = delete; ThreadPool &amp;operator=( const ThreadPool &amp; ) = delete; static ThreadPool &amp;getInstance() &#123; static ThreadPool ins; return ins; &#125; using Task = std::packaged_task&lt;void()&gt;; ~ThreadPool() &#123; stop(); &#125; // NOTE: 用于将任务队列中的任务提交到pool_里面 template &lt;typename F, class... Args&gt; auto commit( F &amp;&amp;func, Args &amp;&amp;...args ) -&gt; std::future&lt;decltype( func( args... ) )&gt; &#123; using RetType = decltype( func( args... ) ); if ( stop_.load() ) &#123; // NOTE: 这里如果触发异常处理，可以通过异常处理来了解状态 return std::future&lt;RetType&gt;&#123;&#125;; &#125; // NOTE:关于这里为什么要使用std::shared_ptr // 1. // 避免对象过早的销毁，我们通常需要在另一个线程中执行task,可能会在创建的作用域之外。 // 2. // 允许对象的共享，比如说，你可以在一个线程中安排一个任务，并在另一个线程中等待该任务完成并获取其结果。 // 这样的话，任务对象就需要在多个线程中共享，而 // std::shared_ptr 正好可以满足这个要求。 auto task = std::make_shared&lt;std::packaged_task&lt;RetType()&gt;&gt;( std::bind( std::forward&lt;F&gt;( func ), std::forward&lt;Args&gt;( args )... ) ); std::future&lt;RetType&gt; ret = task-&gt;get_future(); &#123; std::lock_guard&lt;std::mutex&gt; cv_mt( cv_mt_ ); tasks_.emplace( [task] &#123; ( *task )(); &#125; ); &#125; cv_lock_.notify_one(); return ret; &#125; int idleThreadCount() &#123; return thread_num_; &#125;private: ThreadPool( unsigned int num = 5 ) : stop_( false ) &#123; if ( num &lt; 1 ) &#123; thread_num_ = 1; &#125; else &#123; thread_num_ = num; &#125; start(); &#125; void start() &#123; for ( int i = 0; i &lt; thread_num_; i++ ) &#123; pool_.emplace_back( [this]() &#123; while ( !this-&gt;stop_.load() ) &#123; Task task; std::unique_lock&lt;std::mutex&gt; cv_mt( cv_mt_ ); this-&gt;cv_lock_.wait( cv_mt, [this]() &#123; // NOTE: 当stop_为true,或者任务队列不空时，线程都会醒来。 return this-&gt;stop_.load() || !this-&gt;tasks_.empty(); &#125; ); if ( this-&gt;tasks_.empty() ) &#123; return; &#125; task = std::move( this-&gt;tasks_.front() ); this-&gt;tasks_.pop(); // 拿到一个任务，空闲线程-1 this-&gt;thread_num_--; task(); // NOTE: 拿到一个新任务，进行异步调用，执行任务。 // 任务执行完之后，空闲线程又回来了，空闲线程+1 this-&gt;thread_num_++; &#125; &#125; ); &#125; &#125; void stop() &#123; stop_.store( true ); cv_lock_.notify_all(); for ( auto &amp;td : pool_ ) &#123; if ( td.joinable() ) &#123; std::cout &lt;&lt; &quot;join thread &quot; &lt;&lt; td.get_id() &lt;&lt; std::endl; td.join(); &#125; &#125; &#125;private: std::mutex cv_mt_; std::condition_variable cv_lock_; std::atomic_bool stop_; std::atomic_int thread_num_; std::queue&lt;Task&gt; tasks_; std::vector&lt;std::thread&gt; pool_;&#125;; 注意： 线程池做的任务是并发的、无序的，无法保证有序性 如果执行的任务是强关联或者互斥性很大，建议使用单线程，线程池的意义不大 源码链接

