&quot;;&#125;int main() &#123; std::thread t1(func); t1.join(); return 0;&#125; 如果函数需要传参 12345678910111213141516#include &lt;iostream&gt;#include &lt;thread&gt;void func(std::string name) &#123; std::cout &lt;&lt; name &lt;&lt; &quot;
&quot;;&#125;int main() &#123; std::thread t1(func , &quot;127.0.0.1&quot;); t1.join(); return 0;&#125; 仿函数作为参数 123456class Background_task &#123;public: void operator[](const std::string&amp; str) &#123; std::cout &lt;&lt; str &lt;&lt; &quot;
&quot;; &#125;;&#125;; 注意： 如果采用如下的方式调用函数，编译器一定会报错 12std::thread t1(Background_task());t1.join(); 因为编译器会将t1当作一个函数对象，返回一个std::thread类型的值，函数的参数为一个函数指针，该函数指针返回值为Back_ground_task，参数为void 1std::thread (*)(Background_task (*)()); 修改的方式如下 1234std::thread t1((background_task()));t1.join();std::thread t2&#123;background_task()&#125;;t2.join(); lambda表达式作为参数 12345std::thread t1([](const std::string&amp; str)&#123; std::cout &lt;&lt; str &lt;&lt; &quot;
&quot;;&#125; , &quot;hello world
&quot;);t1.join(); 注意在线程中参数是以拷贝的形式进行传递，因此对于拷贝耗时的对象可以选择用引用或者指针进行传递。但是需要考虑对象的生命周期。因为线程的运行长度可能会超过参数的生命周期，这个时候如果线程还在访问一个已经被销毁的对象就会出现问题 detach 和 join 主要API 一旦启动线程之后，我们必须决定是要等待到这个线程结束(join)，或者直接和主线程独立开来(detach)，我们必须二者选其一。如果std::thread对象销毁时我们还没有触发任何操作，则std::thread对象在析构函数将调用std::terminate()从而导致进程异常退出 join: 调用这个API时，当前线程就会停滞，直到目标线程执行完毕。 detach: 这个API是让目标线程成为守护线程。一旦detach之后，目标线程将独立运行，即便其对应的std::thread对象销毁也不影响线程的执行。并且无法与之通信。 对于这两个接口，都必须是可执行的线程才有意义。可以通过joinable()接口查询是否可以对它们进行join或者detach 管理线程 yield: 通常在自己的主要任务已经完成时，希望让出处理器给其他任务使用 get_id: 返回当前线程的id，可以用来标识不同的线程 sleep_for: 可以让当前线程停滞一段时间 sleep_until: 和sleep_for类似，但是以具体时间点为参数，这两个API都是以chronoapi为基础 123456789101112131415161718192021222324252627282930313233343536#include &lt;iomanip&gt;#include &lt;iostream&gt;#include &lt;thread&gt;#include &lt;sstream&gt;void print_time() &#123; auto now = std::chrono::system_clock::now(); auto in_time_t = std::chrono::system_clock::to_time_t(now); std::stringstream ssin; ssin &lt;&lt; std::put_time(std::localtime(&amp;in_time_t) , &quot;%Y-%m-%d %X&quot;); std::cout &lt;&lt; &quot;now is: &quot; &lt;&lt; ssin.str() &lt;&lt; &quot;
&quot;;&#125;void sleep_thread() &#123; std::this_thread::sleep_for(std::chrono::seconds(3)); std::cout &lt;&lt; &quot;[thread-&quot; &lt;&lt; std::this_thread::get_id() &lt;&lt; &quot;] is waking up
&quot;;&#125;void loop_thread() &#123; for(int i = 0; i &lt; 10; i++) &#123; std::cout &lt;&lt; &quot;[thread-&quot; &lt;&lt; std::this_thread::get_id() &lt;&lt; &quot;] print: &quot; &lt;&lt; i &lt;&lt; &quot;
&quot;; &#125;&#125;int main() &#123; print_time(); std::thread t1(sleep_thread) , t2(loop_thread); t1.join(); t2.detach(); print_time(); return 0;&#125; 线程的归属权 每个线程都有其归属权，也就是说归属给每个变量管理 1234567void func() &#123;&#125;std::thread t1(func); t1是一个线程变量，管理一个线程，该线程执行func()对于std::threadC++不允许拷贝构造和拷贝赋值，所以只能通过移动和局部变量返回的方式将线程变量管理权转移给其他变量管理。 例如下面的例子 1234567891011121314151617181920212223242526272829303132333435363738#include &lt;iostream&gt;#include &lt;thread&gt;#include &lt;chrono&gt;namespace &#123;void func1() &#123; while(true) &#123; std::this_thread::sleep_for(std::chrono::seconds(1)); &#125;&#125;void func2() &#123; while(true) &#123; std::this_thread::sleep_for(std::chrono::seconds(1)); &#125;&#125;&#125;; // namespaceint main() &#123; //1. t1绑定函数func1() std::thread t1(func1); //2. 转移t1的管理的线程给t2，转移后t1无效 std::thread t2 = std::move(t1); //3. t1绑定函数func2() t1 = std::thread(func2); //4. 新建一个线程t3 std::thread t3; //5. 转移t2管理的线程给t3，， t3 = std::move(t2); //6. 转移t3管理的线程给t1 t1 = std::move(t3); // BUG:不可以将一个线程的管理权交给一个已经绑定线程的变量， //否则会触发线程的terminate函数引发崩溃 // t1 = std::move(t3); std::this_thread::sleep_for(std::chrono::seconds(2000)); return 0;&#125; 异常处理当我们启动一个线程之后，如果主线程崩溃，会导致子线程也会异常退出，调用std::terminate()，如果自线程在进行一些重要的操作比如将充值信息入库等，丢失这些信息是很为危险的。所以常用的做法是捕获异常，并且在异常情况下保证子线程稳定运行结束后，主线程抛出异常结束运行 1234567891011121314151617void catch_exception() &#123; int some_local_state = 0; std::function&lt;void()&gt; myfunc = []()&#123; // doing something &#125;; std::thread functhread(myfunc); try&#123; // 本线程做的一些事情，可能引发崩溃 std::this_thread::sleep_for(std::chrono::seconds(1)); &#125; catch (std::exception&amp; e) &#123; functhread.join(); throw std::runtime_error(&quot;ababababa
&quot;); &#125; functhread.join();&#125; 但是用这种方式编码会显得臃肿，可以使用RAII技术，保证线程对象析构的时候等待线程运行结束，回收资源。 12345678910111213141516171819202122232425class thread_guard &#123;private: std::thread&amp; _t;public: explicit thread_guard(std::thread&amp; t) : _t(t) &#123;&#125; ~thread_guard() &#123; if(_t.joinable()) &#123; _t.join(); &#125; &#125; thread_guard(const thread_guard&amp;) = delete; thread_guard&amp; operator=(const thread_guard&amp;) = delete;&#125;;void auto_guard() &#123; int some_local_state = 0; std::function&lt;void()&gt; myfunc = []()&#123; // doing something &#125;; std::thread t1(myfunc); thread_guard guard(t1); std::cout &lt;&lt; &quot;auto guard finish
&quot;;&#125; 慎用隐式转换C++中会有一些隐式转换，例如char*转换为std::string等，这些隐式转换在线程的调用上可能会造成崩溃问题 12345678910void danger_oops(int som_param) &#123; char buffer[1024]; sprintf(buffer, &quot;%i&quot;, som_param); // NOTE:在线程内部将char const* 转化为std::string // 指针常量 char const* 指针本身不能变 // 常量指针 const char * 指向的内容不能变 std::thread t(print_str, 3, buffer); t.detach(); std::cout &lt;&lt; &quot;danger oops finished &quot; &lt;&lt; std::endl;&#125; 在以上代码中，当我们定义一个线程变量thread t时，传递给这个线程参数buffer会被保存到thread的成员变量中。而在线程对象t内部启动并运行线程时，参数才会被传递给调用函数print_str。而此时buffer可能到&#125;就被销毁了。改进方式很简单，我们将参数传递给thread时显示转换成string就可以了，其实相当于拷贝一份过去。 1234567891011 void danger_oops(int som_param) &#123; char buffer[1024]; sprintf(buffer, &quot;%i&quot;, som_param); //在线程内部将char const* 转化为std::string //指针常量 char const* 指针本身不能变 //常量指针 const char * 指向的内容不能变 std::thread t(print_str, 3, std::string(buffer)); t.detach(); std::cout &lt;&lt; &quot;danger oops finished &quot; &lt;&lt; std::endl;&#125; 引用参数在线程要调用的回调函数参数作为引用类型时，需要将参数显式转换为引用对象传递给构造函数，如果采用如下调用会编译失败 1234567891011void change_param(int&amp; param) &#123; ++param;&#125;void ref_oops(int some_param) &#123; std::cout &lt;&lt; &quot;before change , param is &quot; &lt;&lt; some_param &lt;&lt; std::endl; // 需要引用显式转换 std::thread t2(change_param , some_param); t2.join(); std::cout &lt;&lt; &quot;after change , param is &quot; &lt;&lt; some_param &lt;&lt; std::endl;&#125; 即使函数change_param的参数为int&amp;类型，我们传递给t2的构造函数为some_param，也不会达到在change_param函数内部修改关联到外部some_param的效果。因为some_param在传递给thread的构造函数后会转变为右值保存，右值传递给一个左值引用会出问题，所以编译也出了问题。 只需要使用std::ref()就可以解决 12345678910111213void change_param(int&amp; param) &#123; ++param;&#125;void ref_oops(int some_param) &#123; std::cout &lt;&lt; &quot;before change , param is &quot; &lt;&lt; some_param &lt;&lt; std::endl; // 需要引用显式转换 std::thread t2(change_param , std::ref(some_param)); t2.join(); std::cout &lt;&lt; &quot;after change , param is &quot; &lt;&lt; some_param &lt;&lt; std::endl;&#125; 绑定类成员函数有时候我们需要绑定一个类的成员函数。 12345678910111213class X &#123;public: void do_length_work() &#123; std::cout &lt;&lt; &quot;do_length_work&quot; &lt;&lt; std::endl; &#125;&#125;;void bind_class_oops() &#123; X my_x; std::thread t(&amp;X::do_length_work , &amp;my_x); t.join();&#125; 注意，如果thread绑定的是普通函数，可以在函数前加&amp;或者不加&amp;，因为编译器默认将普通函数名作为函数地址，但是如果是绑定类的成员函数，必须加&amp; 1234567void thead_work1(std::string str) &#123; std::cout &lt;&lt; &quot;str is &quot; &lt;&lt; str &lt;&lt; std::endl;&#125;std::string hellostr = &quot;hello world!&quot;;//两种方式都正确std::thread t1(thead_work1, hellostr);std::thread t2(&amp;thead_work1, hellostr); 使用move操作有时候传递给线程的参数是独占的，所谓独占就是不支持拷贝赋值和构造，但是我们可以通过std::move()的方式将参数的所有权转移给线程。 123456789101112void deal_unqiue(std::unique_ptr&lt;int&gt; p) &#123; std::cout &lt;&lt; &quot;unique ptr data is &quot; &lt;&lt; *p &lt;&lt; std::endl; (*p)++; std::cout &lt;&lt; &quot;after unqiue ptr data is &quot; &lt;&lt; *p &lt;&lt; std::endl;&#125;void move_oops() &#123; auto p = std::make_unique&lt;int&gt;(100); std::thread t(deal_unqiue , std::move(p)); t.join();&#125; 一次调用在一些情况下，我们有些任务需要执行一次，并且我们只希望它执行一次，例如资源的初始化人物。这个时候就可以用到std::call_once和std::once_flag。这两个接口保证即便在多线程的环境下，相应的函数也只会调用一次。 例如下面的代码，有四个线程会执行init()函数，但是只有一个线程会执行。 1234567891011121314151617181920212223242526#include &lt;iostream&gt;#include &lt;thread&gt;#include &lt;mutex&gt;void init() &#123; std::cout &lt;&lt; &quot;Initializing....&quot; &lt;&lt; std::endl;&#125;void worker(std::once_flag&amp; flag) &#123; std::call_once(flag, init);&#125;int main() &#123; std::once_flag flag; std::thread t1( worker, std::ref(flag) ); std::thread t2( worker, std::ref(flag) ); std::thread t3( worker, std::ref(flag) ); std::thread t4( worker, std::ref(flag) ); std::thread t5( worker, std::ref(flag) ); t1.join(); t2.join(); t3.join(); t4.join(); t5.join(); return 0;&#125; 注意，我们无法确定哪个线程执行了init()函数，但是我们也不需要关心，因为只要有一个线程执行了init()函数就可以了 并发任务实例：需要计算某个范围内所有数的平方根总和 123456789101112131415161718192021222324252627282930313233#include &lt;iostream&gt;#include &lt;thread&gt;#include &lt;mutex&gt;#include &lt;cmath&gt;#include &lt;chrono&gt;static int MAX = 10e8;static double sum = 0;void func(int min , int max) &#123; for(int i = min ; i &lt;= max; i++) &#123; sum += sqrt(i); &#125;&#125;void task(int min , int max) &#123; // 得到调用func之前的时间 auto start_time = std::chrono::steady_clock::now(); sum = 0; func(min , max); // 得到调用后func之后的时间 auto end_time = std::chrono::steady_clock::now(); // 得到持续的时间 auto ms = std::chrono::duration_cast&lt;std::chrono::milliseconds&gt;(end_time - start_time).count(); std::cout &lt;&lt; &quot;Task finish, &quot; &lt;&lt; ms &lt;&lt; &quot; ms consumed , Result: &quot; &lt;&lt; sum &lt;&lt; &quot;
&quot;;&#125;int main() &#123; task(1 , MAX); return 0;&#125; 输出为 1Task finish, 1821 ms consumed , Result: 2.10819e+13 很明显上面的计算使用单线程性能太差，可以使用并发进行。 先获取当前硬件支持多少个线程并行执行 根据处理器情况决定线程数量 对于每一个线程都通过func()函数来完成任务，并划分一部分数据给它处理 等待每一个线程结束。 123456789101112131415161718192021void concurrent_task(int min , int max) &#123; auto start_time = std::chrono::steady_clock::nowxainshi(); // 得到线程数量 unsigned int concurrent_count = std::thread::hardware_concurrency(); std::cout &lt;&lt; &quot;hardware_concurrency: &quot; &lt;&lt; concurrent_count &lt;&lt; &quot;
